# Semantic version bumper — parses, bumps, and generates changelogs from conventional commits

function Get-SemanticVersion {
    # Parse a semantic version string from a file (VERSION or package.json)
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if (-not (Test-Path $Path)) {
        throw "Version file not found: $Path"
    }

    $content = Get-Content -Path $Path -Raw
    # Match semver pattern (major.minor.patch)
    if ($content -match '(\d+)\.(\d+)\.(\d+)') {
        return [PSCustomObject]@{
            Major = [int]$Matches[1]
            Minor = [int]$Matches[2]
            Patch = [int]$Matches[3]
        }
    }
    throw "No valid semantic version found in: $Path"
}

