function Get-BumpType {
    # Determine the bump type (major, minor, patch) from conventional commit messages.
    # Priority: breaking > feat > fix/other
    param(
        [Parameter(Mandatory)]
        [string[]]$CommitMessages
    )

    if ($CommitMessages.Count -eq 0) {
        throw "No commit messages provided"
    }

    $hasBreaking = $false
    $hasFeat = $false

    foreach ($msg in $CommitMessages) {
        # Breaking change: "!" after type or "BREAKING CHANGE" anywhere in message
        if ($msg -match '^\w+!:' -or $msg -match 'BREAKING CHANGE') {
            $hasBreaking = $true
            break
        }
        if ($msg -match '^feat[\(:]') {
            $hasFeat = $true
        }
    }

    if ($hasBreaking) { return 'major' }
    if ($hasFeat)     { return 'minor' }
    return 'patch'
}

